def logprob_to_accuracy(lp):
    if lp >= -0.25: return "High", "acc-high"
    elif lp >= -0.65: return "Medium", "acc-med"
    else: return "Low", "acc-low"

def _norm_text(s: str) -> str:
    s = re.sub(r"\s+", " ", (s or "").strip().lower())
    s = re.sub(r"[^\w\s]", "", s)
    return s

def cleanup_repetitions(text: str) -> str:
    text = re.sub(r"\s+", " ", (text or "").strip())
    if not text:
        return text

    parts = [p.strip() for p in re.split(r"(?<=[.!?])\s+", text) if p.strip()]
    dedup_parts, prev_norm = [], ""
    for p in parts:
        n = _norm_text(p)
        if n and n == prev_norm:
            continue
        dedup_parts.append(p)
        prev_norm = n
    if dedup_parts:
        text = " ".join(dedup_parts)

    words = text.split()
    if len(words) >= 12:
        out, i = [], 0
        while i < len(words):
            collapsed = False
            for n in (6, 5, 4, 3):
                if i + 2 * n <= len(words):
                    g1 = [w.lower() for w in words[i:i+n]]
                    g2 = [w.lower() for w in words[i+n:i+2*n]]
                    if g1 == g2:
                        out.extend(words[i:i+n])
                        j = i + 2 * n
                        while j + n <= len(words) and [w.lower() for w in words[j:j+n]] == g1:
                            j += n
                        i = j
                        collapsed = True
                        break
            if not collapsed:
                out.append(words[i]); i += 1
        text = " ".join(out)
    return text

def dedupe_overlap_segments(segments):
    if not segments:
        return []
    segs = sorted(segments, key=lambda s: (s.get("start", 0.0), s.get("end", 0.0)))
    out = [segs[0]]
    for seg in segs[1:]:
        prev = out[-1]
        same_text = _norm_text(seg.get("text", "")) == _norm_text(prev.get("text", ""))
        near_time = abs(float(seg.get("start", 0.0)) - float(prev.get("start", 0.0))) < 1.2
        inside_prev = float(seg.get("end", 0.0)) <= float(prev.get("end", 0.0)) + 0.05
        if same_text and (near_time or inside_prev):
            continue
        out.append(seg)
    return out

def turn_quality_score(turn):
    base = float(np.mean(turn.get("logprobs", [-0.7])))
    toks = re.findall(r"\b\w+\b", (turn.get("text", "") or "").lower())
    if not toks:
        return base - 0.2
    unique_ratio = len(set(toks)) / max(1, len(toks))
    if len(toks) >= 12 and unique_ratio < 0.45:
        base -= 0.22
    if len(toks) >= 20 and unique_ratio < 0.35:
        base -= 0.18
    return base

def auto_speaker_gap(segments):
    gaps = sorted(
        s2["start"] - s1["end"]
        for s1, s2 in zip(segments, segments[1:])
        if s2["start"] - s1["end"] > 0.15
    )
    if not gaps:
        return 1.5
    p75 = gaps[int(len(gaps) * 0.75)]
    return max(0.8, min(3.5, p75))

def build_speaker_turns(segments, gap):
    turns, cur = [], None
    for seg in segments:
        if cur is None:
            cur = {"start": seg["start"], "end": seg["end"], "text": seg["text"].strip(),
                   "logprobs": [seg.get("avg_logprob", -0.3)], "speaker_idx": 0}
        elif seg["start"] - cur["end"] >= gap:
            turns.append(cur)
            cur = {"start": seg["start"], "end": seg["end"], "text": seg["text"].strip(),
                   "logprobs": [seg.get("avg_logprob", -0.3)], "speaker_idx": cur["speaker_idx"] + 1}
        else:
            cur["end"] = seg["end"]
            cur["text"] += " " + seg["text"].strip()
            cur["logprobs"].append(seg.get("avg_logprob", -0.3))
    if cur:
        turns.append(cur)
    return turns

def _segment_voice_embedding(audio, start_s, end_s, sample_rate=16000):
    s = max(0, int(start_s * sample_rate))
    e = min(len(audio), int(end_s * sample_rate))
    if e - s < int(0.35 * sample_rate):
        return None
    seg_audio = audio[s:e]
    mel = whisper.log_mel_spectrogram(seg_audio, n_mels=80).numpy()
    if mel.shape[1] < 3:
        return None
    emb = np.concatenate([mel.mean(axis=1), mel.std(axis=1)]).astype(np.float32)
    norm = np.linalg.norm(emb) + 1e-8
    return emb / norm

def _kmeans_np(x, k, seed=42, max_iter=40):
    rng = np.random.default_rng(seed)
    n = len(x)
    if k <= 1 or n == 0:
        return np.zeros(n, dtype=int)
    centers = x[rng.choice(n, size=k, replace=False)]
    labels = np.zeros(n, dtype=int)
    for _ in range(max_iter):
        dists = ((x[:, None, :] - centers[None, :, :]) ** 2).sum(axis=2)
        new_labels = dists.argmin(axis=1)
        if np.array_equal(new_labels, labels):
            break
        labels = new_labels
        for c in range(k):
            members = x[labels == c]
            centers[c] = members.mean(axis=0) if len(members) else x[rng.integers(0, n)]
    return labels

def _silhouette_score(x, labels):
    n = len(x)
    if n < 3:
        return -1.0
    dmat = np.sqrt(((x[:, None, :] - x[None, :, :]) ** 2).sum(axis=2))
    score_sum = 0.0
    for i in range(n):
        same = labels == labels[i]
        same_count = int(same.sum())
        if same_count <= 1:
            continue
        a = dmat[i, same].sum() / (same_count - 1)
        b = np.inf
        for cl in np.unique(labels):
            if cl == labels[i]:
                continue
            other = labels == cl
            if other.any():
                b = min(b, dmat[i, other].mean())
        if np.isfinite(b):
            score_sum += (b - a) / max(a, b, 1e-8)
    return score_sum / n

def build_diarized_turns(segments, audio, sample_rate, gap, max_speakers=4):
    if not segments:
        return [], False
    usable_idx, feats = [], []
    for i, seg in enumerate(segments):
        emb = _segment_voice_embedding(audio, seg["start"], seg["end"], sample_rate=sample_rate)
        if emb is not None:
            usable_idx.append(i)
            feats.append(emb)
    if len(feats) < 2:
        return build_speaker_turns(segments, gap), False
    x = np.vstack(feats)
    k_max = min(max_speakers, len(x))
    best_labels = np.zeros(len(x), dtype=int)
    best_score = -2.0
    for k in range(2, k_max + 1):
        labels = _kmeans_np(x, k)
        score = _silhouette_score(x, labels)
        if score > best_score:
            best_score = score
            best_labels = labels
    speaker_per_segment = np.zeros(len(segments), dtype=int)
    for idx, lab in zip(usable_idx, best_labels):
        speaker_per_segment[idx] = int(lab)
    for i in range(1, len(segments)):
        if i not in usable_idx:
            speaker_per_segment[i] = speaker_per_segment[i - 1]
    turns, cur = [], None
    for i, seg in enumerate(segments):
        spk = int(speaker_per_segment[i])
        if cur is None:
            cur = {"start": seg["start"], "end": seg["end"], "text": seg["text"].strip(),
                   "logprobs": [seg.get("avg_logprob", -0.3)], "speaker_idx": spk}
            continue
        gap_hit = seg["start"] - cur["end"] >= gap
        speaker_switch = spk != cur["speaker_idx"]
        if gap_hit or speaker_switch:
            turns.append(cur)
            cur = {"start": seg["start"], "end": seg["end"], "text": seg["text"].strip(),
                   "logprobs": [seg.get("avg_logprob", -0.3)], "speaker_idx": spk}
        else:
            cur["end"] = seg["end"]
            cur["text"] += " " + seg["text"].strip()
            cur["logprobs"].append(seg.get("avg_logprob", -0.3))
    if cur:
        turns.append(cur)
    remap, nxt = {}, 0
    for t in turns:
        raw = t["speaker_idx"]
        if raw not in remap:
            remap[raw] = nxt
            nxt += 1
        t["speaker_idx"] = remap[raw]
    return turns, True

@st.cache_resource(show_spinner=False)
def load_pyannote_pipeline(hf_token):
    if not PYANNOTE_AVAILABLE or not hf_token:
        return None
    return PyannotePipeline.from_pretrained("pyannote/speaker-diarization-3.1", token=hf_token)

def build_true_diarized_turns(segments, diarization, gap):
    if not segments:
        return [], False
    diar_spans = [(float(t.start), float(t.end), str(spk))
                  for t, _, spk in diarization.itertracks(yield_label=True)]
    if not diar_spans:
        return [], False
    turns, cur = [], None
    last_speaker = diar_spans[0][2]
    for seg in segments:
        s0, s1 = float(seg["start"]), float(seg["end"])
        best_spk, best_overlap = None, 0.0
        for d0, d1, spk in diar_spans:
            overlap = max(0.0, min(s1, d1) - max(s0, d0))
            if overlap > best_overlap:
                best_overlap = overlap
                best_spk = spk
        if best_spk is None:
            best_spk = last_speaker
        last_speaker = best_spk
        if cur is None:
            cur = {"start": s0, "end": s1, "text": seg["text"].strip(),
                   "logprobs": [seg.get("avg_logprob", -0.3)], "speaker_key": best_spk}
            continue
        if s0 - cur["end"] >= gap or best_spk != cur["speaker_key"]:
            turns.append(cur)
            cur = {"start": s0, "end": s1, "text": seg["text"].strip(),
                   "logprobs": [seg.get("avg_logprob", -0.3)], "speaker_key": best_spk}
        else:
            cur["end"] = s1
            cur["text"] += " " + seg["text"].strip()
            cur["logprobs"].append(seg.get("avg_logprob", -0.3))
    if cur:
        turns.append(cur)
    remap, nxt = {}, 0
    for t in turns:
        key = t.pop("speaker_key")
        if key not in remap:
            remap[key] = nxt
            nxt += 1
        t["speaker_idx"] = remap[key]
    return turns, True


